---战斗显示对象管理
---@class LFightObjectCtrl
local LFightObjectCtrl = LxClass("LFightObjectCtrl",nil)
-----------------------------------------------------------------
local LFightObject = LXImport("..View.LFightObject")

-----------------------------------------------------------------
---@param battleUnit LFightUnit
function LFightObjectCtrl:LFightObjectCtrl(battleUnit)
	self._battleUnit = battleUnit
	--所有对象列表{LFightObject,LFightObject,...}
	---@type LFightObject[]
	self._objList = {}
	--当前对象列表{key=LFightObject,key=LFightObject,...}
	---@type table<string,LFightObject>
	self._objMap = {}

	--己方队伍
	---@type LFightObject[]
	self._teamAList = {}

	--敌方队伍
	self._teamBList = {}

end

-----------------------------------------------------------------
function LFightObjectCtrl:InitData()

end

---@return LFightObject
function LFightObjectCtrl:MakeObject(heroData, parentTrans, gridPos, completeFunc)
	local obj = LFightObject:New(self._battleUnit)
	if not obj:Create(heroData, parentTrans, gridPos, completeFunc) then
		return nil
	end
	return obj
end

-----------------------------------------------------------------
---@param obj LFightObject
function LFightObjectCtrl:AddObject(obj)
	local id = obj:GetId()
	if self._objMap[id] then
		LogError("duplicate battleobj id"..tostring(id))
	end
	self._objMap[id] = obj

	table.insert(self._objList,obj)

	local side = obj:GetSide()
	if side == LFightConst.SIDE_TEAM_A then
		table.insert(self._teamAList,obj)
	else
		table.insert(self._teamBList,obj)
	end

	return true
end

function LFightObjectCtrl:DestroyObjById(id)
	local obj = self._objMap[id]
	self._objMap[id] = nil
	if not obj then
		return
	end
	obj:Destroy()
	table.removeidata(self._objList,obj)

	local side = obj:GetSide()
	if side == LFightConst.SIDE_TEAM_A then
		table.removeidata(self._teamAList,obj)
	else
		table.removeidata(self._teamBList,obj)
	end
	return true
end

-----------------------------------------------------------------
function LFightObjectCtrl:OnRun(time)
	for k,v in ipairs(self._objList) do
		v:OnRun(time)
	end
end
-----------------------------------------------------------------
---获取相反方列表
function LFightObjectCtrl:GetOppositeTeamBySide(side)
	local getSide = LFightConst.SIDE_TEAM_A
	if side == LFightConst.SIDE_TEAM_A then
		getSide = LFightConst.SIDE_TEAM_B
	end

	return self:GetTeamBySide(getSide)
end

--获取同一方队伍列表
function LFightObjectCtrl:GetTeamBySide(side)
	local list = nil
	if side == LFightConst.SIDE_TEAM_A then
		list = self._teamAList
	else
		list = self._teamBList
	end

	local temp= {}
	for k,v in ipairs(list) do
		if v:GetObjectType() == LFightConst.OBJ_NORMAL then
			table.insert(temp,v)
		end
	end

	return temp
end

--获取同一方队伍列表
function LFightObjectCtrl:GetTeamBySidePet(side)
	local list = nil
	if side == LFightConst.SIDE_TEAM_A then
		list = self._teamAList
	else
		list = self._teamBList
	end

	local temp= {}
	for k,v in ipairs(list) do
		local objType = v:GetObjectType()
		if objType == LFightConst.OBJ_PET or objType ==LFightConst.OBJ_NORMAL then
			table.insert(temp,v)
		end
	end

	return temp
end

--获取对象列表
---@return LFightObject[]
function LFightObjectCtrl:GetObjectList()
	return self._objList
end

--根据唯一id获取对象
---@return LFightObject
function LFightObjectCtrl:GetObjectById(id)
	return self._objMap[id]
end

-----------------------------------------------------------------
function LFightObjectCtrl:ClearAllObject()
	local objList = self._objList
	if objList  then
		for k,v in ipairs(objList) do
			v:Destroy()
		end
	end
	self._objList = {}
	self._objMap = {}
	self._teamAList = {}
	self._teamBList = {}
end

function LFightObjectCtrl:IsAllDeadTweenEnd()
	local objList = self._objList
	if(objList) then
		for k,v in ipairs(self._objList) do
			local objData  = v:GetHeroData()
			if objData:GetArtifactType() == LFightConst.OBJ_NORMAL then
				local isDead = v:IsDead()
				local isDeadTweenEnd = v:IsDeadTweenEnd()
				if isDead and not isDeadTweenEnd then
					return false
				end
			end
		end
	end

	return true
end

function LFightObjectCtrl:UpdateHeroMap()
	self._heroMapByIndex = {
		[LFightConst.SIDE_TEAM_A] = {},
		[LFightConst.SIDE_TEAM_B] = {},
	}

	for k,v in pairs(self._objMap) do
		if v:IsOnGridObj() then
			local side = v:GetActOn()
			local index = v:GetIndex()
			self._heroMapByIndex[side][index] = v
		end
	end
end

