function LFightObjectCtrl:DestroyBySide(side)
    local teamList = nil
    if side == LFightConst.SIDE_TEAM_A then
        teamList = self._teamAList
        self._teamAList = {}
    else
        teamList = self._teamBList
        self._teamBList = {}
    end

    local cnt = #teamList
    for k=cnt,1,-1 do
        local obj = teamList[k]
        table.removeidata(self._objList,obj)
        local id = obj:GetId()
        self._objMap[id] = nil
    end

    for k,v in ipairs(teamList) do
        v:Destroy()
    end
end


-----------------------------------------------------------------
function LFightObjectCtrl:Destroy()
	self:ClearAllObject()
	table.removeall(self)
end
-----------------------------------------------------------------

return LFightObjectCtrl